INSERT INTO `clause_library` VALUES (1,1,7,'4.1','Context review','Internal audit checklist question for FSSC 22000 Version 6: verify that controls for context review are defined, implemented, monitored and supported by retained evidence. Do not treat this text as a substitute for licensed standard wording.','Evidence reviewed indicates the process for strategic and operational context is defined, implemented and maintained.','The organization demonstrated effective practice in strategic and operational context, with clear evidence and responsible ownership.','The organization may improve consistency, evidence retention or performance monitoring related to strategic and operational context.','Isolated weakness or incomplete evidence was found in strategic and operational context, with limited impact on system effectiveness.','Systemic absence, repeated failure or ineffective control was found in strategic and operational context, affecting confidence in system effectiveness.','Policies, procedures, records, interviews, sampled transactions, monitoring results, corrective actions and management review outputs.','Verify implementation through records, interviews and sampling. Confirm ownership, criteria, evidence retention and follow-up of actions.','medium','stage1,stage2,surveillance,recertification',1,'2026-07-05 12:27:26','2026-07-06 15:03:26'),(2,1,7,'4.2','Interested party needs','Internal audit checklist question for FSSC 22000 Version 6: verify that controls for interested party needs are defined, implemented, monitored and supported by retained evidence. Do not treat this text as a substitute for licensed standard wording.','Evidence reviewed indicates the process for interested party requirements is defined, implemented and maintained.','The organization demonstrated effective practice in interested party requirements, with clear evidence and responsible ownership.','The organization may improve consistency, evidence retention or performance monitoring relat